INSERT INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('aqidatulawam', 1, 'Muqaddimah', 'المقدمة');
INSERT INTO pesantren_matn (bab_id, matn_order, title_id, text_ar, translation_id) SELECT id, 1, 'Bait 1', 'أَبْـدَأُ بِـاسْمِ اللهِ وَالرَّحْـمَنِ (1) وَبِالرَّحِـيْـمِ دَائـِمِ اْلإِحْـسَانِ', 'Saya (Mushonnif / Pengarang Kitab) memulai dengan nama Allah, Dzat yang maha pengasih, dan Maha Penyayang yang senatiasa memberikan kenikmatan tiada putusnya' FROM pesantren_bab WHERE kitab_slug = 'aqidatulawam' AND bab_order = 1;
INSERT INTO pesantren_matn (bab_id, matn_order, title_id, text_ar, translation_id) SELECT id, 2, 'Bait 2', 'فَالْحَـمْـدُ ِللهِ الْـقَدِيْمِ اْلأَوَّلِ (2) اَلآخِـرِ الْبَـاقـِيْ بِلاَ تَحَـوُّلِ', 'Maka segala puji bagi Allah Yang Maha Dahulu, Yang Maha Awal, Yang Maha Akhir, Yang Maha Tetap tanpa ada perubahan' FROM pesantren_bab WHERE kitab_slug = 'aqidatulawam' AND bab_order = 1;
INSERT INTO pesantren_matn (bab_id, matn_order, title_id, text_ar, translation_id) SELECT id, 3, 'Bait 3', 'ثُمَّ الـصَّلاَةُ وَالسَّلاَمُ سَـرْمَدَا (3) عَلَى الـنَّـبِيِّ خَيْرِ مَنْ قَدْ وَحَّدَا', 'Kemudian, semoga sholawat dan salam senantiasa tercurahkan pada Nabi sebaik-baiknya orang yang mengEsakan Allah' FROM pesantren_bab WHERE kitab_slug = 'aqidatulawam' AND bab_order = 1;
INSERT INTO pesantren_matn (bab_id, matn_order, title_id, text_ar, translation_id) SELECT id, 4, 'Bait 4', 'وَآلِهِ وَصَـحْبِهِ وَمَـنْ تَـبِـعْ (4) سَـبِيْلَ دِيْنِ الْحَقِّ غَيْرَ مُـبْـتَدِعْ', 'Dan keluarganya, para sahabatnya dan orang-orang yang mengikuti jalan agama secara benar bukan orang-orang yang berbuat bid''ah' FROM pesantren_bab WHERE kitab_slug = 'aqidatulawam' AND bab_order = 1;
INSERT INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('aqidatulawam', 2, 'Sifat-sifat Allah (20 Sifat)', 'صفات الله');
INSERT INTO pesantren_matn (bab_id, matn_order, title_id, text_ar, translation_id) SELECT id, 1, 'Bait 5', 'وَبَعْدُ فَاعْلَمْ بِوُجُوْبِ الْمَعْرِفَـهْ (5) مِنْ وَاجِـبٍ ِللهِ عِشْـرِيْنَ صِفَهْ', 'Dan setelahnya ketahuilah dengan yakin bahwa Allah itu mempunyai 20 sifat wajib' FROM pesantren_bab WHERE kitab_slug = 'aqidatulawam' AND bab_order = 2;
INSERT INTO pesantren_matn (bab_id, matn_order, title_id, text_ar, translation_id) SELECT id, 2, 'Bait 6', 'فَاللهُ مَوْجُـوْدٌ قَـدِيْمٌ بَاقِـي (6) مُخَالـِفٌ لِلْـخَـلْقِ بِاْلإِطْلاَقِ', 'Allah itu Ada, Qodim, Baqi dan berbeda dengan makhlukNya secara mutlak' FROM pesantren_bab WHERE kitab_slug = 'aqidatulawam' AND bab_order = 2;
INSERT INTO pesantren_matn (bab_id, matn_order, title_id, text_ar, translation_id) SELECT id, 3, 'Bait 7', 'وَقَـائِمٌ غَـنِيْ وَوَاحِـدٌ وَحَيّ (7) قَـادِرْ مُـرِيْـدٌ عَـالِمٌ بِكُلِّ شَيْ', 'Berdiri sendiri, Maha Kaya, Maha Esa, Maha Hidup, Maha Kuasa, Maha Menghendaki, Maha Mengetahui atas segala sesuatu' FROM pesantren_bab WHERE kitab_slug = 'aqidatulawam' AND bab_order = 2;
INSERT INTO pesantren_matn (bab_id, matn_order, title_id, text_ar, translation_id) SELECT id, 4, 'Bait 8', 'سَـمِـيْعٌ اْلبَصِـيْرُ وَالْمُتَكَلِّـمُ (8) لَهُ صِـفَاتٌ سَـبْعَـةٌ تَـنْـتَظِمُ', 'Maha Mendengar, Maha Melihat, Maha Berbicara, Allah mempunyai 7 sifat yang tersusun' FROM pesantren_bab WHERE kitab_slug = 'aqidatulawam' AND bab_order = 2;
INSERT INTO pesantren_matn (bab_id, matn_order, title_id, text_ar, translation_id) SELECT id, 5, 'Bait 9', 'فَقُـدْرَةٌ إِرَادَةٌ سـَمْـعٌ بـَصَرْ (9) حَـيَـاةٌ الْعِلْـمُ كَلاَمٌ اسْـتَمَرْ', 'yaitu Berkuasa, Menghendaki, Mendengar, Melihat, Hidup, Mempunyai Ilmu, Berbicara secara terus berlangsung' FROM pesantren_bab WHERE kitab_slug = 'aqidatulawam' AND bab_order = 2;
INSERT INTO pesantren_matn (bab_id, matn_order, title_id, text_ar, translation_id) SELECT id, 6, 'Bait 10', 'وَجَائـِزٌ بِـفَـضْـلِهِ وَ عَدْلِهِ (10) تَـرْكٌ لـِكُلِّ مُمْـكِـنٍ كَفِعْلِهِ', 'Dengan karunia dan keadilanNya, Allah memiliki sifat boleh (wenang) yaitu boleh mengerjakan sesuatu atau meninggalkannya' FROM pesantren_bab WHERE kitab_slug = 'aqidatulawam' AND bab_order = 2;
INSERT INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('aqidatulawam', 3, 'Sifat Para Rasul', 'صفات الرسل');
INSERT INTO pesantren_matn (bab_id, matn_order, title_id, text_ar, translation_id) SELECT id, 1, 'Bait 11', 'أَرْسَـلَ أَنْبِيَا ذَوِي فَـطَـانَـهْ (11) بِالصِّـدْقِ وَالتَـبْلِـيْغِ وَاْلأَمَانَهْ', 'Allah telah mengutus para nabi yang memiliki 4 sifat yang wajib yaitu cerdas, jujur, menyampaikan (risalah) dan dipercaya' FROM pesantren_bab WHERE kitab_slug = 'aqidatulawam' AND bab_order = 3;
INSERT INTO pesantren_matn (bab_id, matn_order, title_id, text_ar, translation_id) SELECT id, 2, 'Bait 12', 'وَجَـائِزٌ فِي حَـقِّهِمْ مِنْ عَرَضِ (12) بِغَيْـرِ نَقْصٍ كَخَـفِيْفِ الْمَرَضِ', 'Dan boleh didalam hak Rosul dari sifat manusia tanpa mengurangi derajatnya,misalnya sakit yang ringan' FROM pesantren_bab WHERE kitab_slug = 'aqidatulawam' AND bab_order = 3;
INSERT INTO pesantren_matn (bab_id, matn_order, title_id, text_ar, translation_id) SELECT id, 3, 'Bait 13', 'عِصْـمَـتُهُمْ كَسَائِرِ الْمَلاَئِكَهْ (13) وَاجِـبَـةٌ وَفَاضَلُوا الْمَـلاَئِكَهْ', 'Mereka mendapat penjagaan Allah (dari perbuatan dosa) seperti para malaikat seluruhnya. (Penjagaan itu) wajib bahkan para Nabi lebih utama dari para malaikat' FROM pesantren_bab WHERE kitab_slug = 'aqidatulawam' AND bab_order = 3;
INSERT INTO pesantren_matn (bab_id, matn_order, title_id, text_ar, translation_id) SELECT id, 4, 'Bait 14', 'وَالْمُسْـتَحِيْلُ ضِدُّ كُلِّ وَاجِبِ (14) فَاحْفَظْ لِخَمْسِـيْنَ بِحُكْمٍ وَاجِبِ', 'Dan sifat mustahil adalah lawan dari sifat yang wajib maka hafalkanlah 50 sifat itu sebagai ketentuan yang wajib' FROM pesantren_bab WHERE kitab_slug = 'aqidatulawam' AND bab_order = 3;
INSERT INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('aqidatulawam', 4, '25 Nabi & Rasul', 'الأنبياء والرسل');
INSERT INTO pesantren_matn (bab_id, matn_order, title_id, text_ar, translation_id) SELECT id, 1, 'Bait 15', 'تَفْصِيْلُ خَمْسَةٍ وَعِشْـرِيْنَ لَزِمْ (15) كُـلَّ مُـكَلَّـفٍ فَحَقِّقْ وَاغْـتَنِمْ', 'Adapun rincian nama para Rosul ada 25 itu wajib diketahui bagi setiap mukallaf, maka yakinilah dan ambilah keuntungannya' FROM pesantren_bab WHERE kitab_slug = 'aqidatulawam' AND bab_order = 4;
INSERT INTO pesantren_matn (bab_id, matn_order, title_id, text_ar, translation_id) SELECT id, 2, 'Bait 16', 'هُمْ آدَمٌ اِدْرِيْسُ نُوْحٌ هُـوْدُ مَعْ (16) صَالِـحْ وَإِبْرَاهِـيْـمُ كُلٌّ مُـتَّبَعْ', 'Mereka adalah Nabi Adam, Idris, Nuh, Hud serta Sholeh, Ibrahim ( yang masing-masing diikuti berikutnya)' FROM pesantren_bab WHERE kitab_slug = 'aqidatulawam' AND bab_order = 4;
INSERT INTO pesantren_matn (bab_id, matn_order, title_id, text_ar, translation_id) SELECT id, 3, 'Bait 17', 'لُوْطٌ وَاِسْـمَاعِيْلُ اِسْحَاقُ كَذَا (17) يَعْقُوبُ يُوسُـفُ وَأَيُّوْبُ احْتَذَى', 'Luth, Ismail dan Ishaq demikian pula Ya''qub, Yusuf dan Ayyub dan selanjutnya' FROM pesantren_bab WHERE kitab_slug = 'aqidatulawam' AND bab_order = 4;
INSERT INTO pesantren_matn (bab_id, matn_order, title_id, text_ar, translation_id) SELECT id, 4, 'Bait 18', 'شُعَيْبُ هَارُوْنُ وَمُوْسَى وَالْيَسَعْ (18) ذُو الْكِـفْلِ دَاوُدُ سُلَيْمَانُ اتَّـبَعْ', 'Syuaib, Harun, Musa dan Alyasa'', Dzulkifli, Dawud, Sulaiman yang diikuti' FROM pesantren_bab WHERE kitab_slug = 'aqidatulawam' AND bab_order = 4;
INSERT INTO pesantren_matn (bab_id, matn_order, title_id, text_ar, translation_id) SELECT id, 5, 'Bait 19', 'إلْيَـاسُ يُوْنُسْ زَكَرِيـَّا يَحْيَى (19) عِيْسَـى وَطَـهَ خَاتِمٌ دَعْ غَـيَّا', 'Ilyas, Yunus, Zakaria, Yahya, Isa dan Thaha (Muhammad) sebagai penutup, maka tinggalkanlah jalan yang menyimpang dari kebenaran' FROM pesantren_bab WHERE kitab_slug = 'aqidatulawam' AND bab_order = 4;
INSERT INTO pesantren_matn (bab_id, matn_order, title_id, text_ar, translation_id) SELECT id, 6, 'Bait 20', 'عَلَـيْهِمُ الصَّـلاَةُ وَالسَّـلاَمُ (20) وَآلِـهِمْ مـَا دَامَـتِ اْلأَيـَّـامُ', 'Semoga sholawat dan salam terkumpulkan pada mereka dan keluarga mereka sepanjang masa' FROM pesantren_bab WHERE kitab_slug = 'aqidatulawam' AND bab_order = 4;
INSERT INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('aqidatulawam', 5, 'Iman kepada Malaikat', 'الإيمان بالملائكة');
INSERT INTO pesantren_matn (bab_id, matn_order, title_id, text_ar, translation_id) SELECT id, 1, 'Bait 21', 'وَالْمَـلَكُ الَّـذِيْ بِلاَ أَبٍ وَأُمْ (21) لاَ أَكْلَ لاَ شُـرْبَ وَلاَ نَوْمَ لَـهُمْ', 'Adapun para malaikat itu tetap tanpa bapak dan ibu, tidak makan dan tidak minum serta tidak tidur' FROM pesantren_bab WHERE kitab_slug = 'aqidatulawam' AND bab_order = 5;
INSERT INTO pesantren_matn (bab_id, matn_order, title_id, text_ar, translation_id) SELECT id, 2, 'Bait 22', 'تَفْـصِـيْلُ عَشْرٍ مِنْهُمُ جِبْرِيْلُ (22) مِـيْـكَـالُ اِسْـرَافِيْلُ عِزْرَائِيْلُ', 'Secara terperinci mereka ada 10, yaitu Jibril, Mikail, Isrofil, dan Izroil' FROM pesantren_bab WHERE kitab_slug = 'aqidatulawam' AND bab_order = 5;
INSERT INTO pesantren_matn (bab_id, matn_order, title_id, text_ar, translation_id) SELECT id, 3, 'Bait 23', 'مُنْـكَرْ نَكِـيْرٌ وَرَقِيْبٌ وَكَذَا (23) عَتِـيْدٌ مَالِكٌ ورِضْوَانُ احْتَـذَى', 'Munkar, Nakiir, dan Roqiib, demikian pula ''Atiid, Maalik, dan Ridwan dan selanjutnya' FROM pesantren_bab WHERE kitab_slug = 'aqidatulawam' AND bab_order = 5;
INSERT INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('aqidatulawam', 6, 'Kitab Suci & Rukun Iman', 'الكتب السماوية والإيمان');
INSERT INTO pesantren_matn (bab_id, matn_order, title_id, text_ar, translation_id) SELECT id, 1, 'Bait 24', 'أَرْبَـعَـةٌ مِنْ كُتُبٍ تَـفْصِيْلُهَا (24) تَوْارَةُ مُوْسَى بِالْهُدَى تَـنْـزِيْلُهَا', 'Empat dari Kitab-Kitab Suci Allah secara terperinci adalah Taurat bagi Nabi Musa diturunkan dengan membawa petunjuk' FROM pesantren_bab WHERE kitab_slug = 'aqidatulawam' AND bab_order = 6;
INSERT INTO pesantren_matn (bab_id, matn_order, title_id, text_ar, translation_id) SELECT id, 2, 'Bait 25', 'زَبُـوْرُ دَاوُدَ وَاِنْجِـيْـلُ عَلَى (25) عِيْـسَى وَفُـرْقَانُ عَلَى خَيْرِ الْمَلاَ', 'Zabur bagi Nabi Dawud dan Injil bagi Nabi Isa dan AlQur''an bagi sebaik-baik kaum (Nabi Muhammad SAW)' FROM pesantren_bab WHERE kitab_slug = 'aqidatulawam' AND bab_order = 6;
INSERT INTO pesantren_matn (bab_id, matn_order, title_id, text_ar, translation_id) SELECT id, 3, 'Bait 26', 'وَصُحُـفُ الْخَـلِيْلِ وَالْكَلِيْمِ (26) فِيْهَـا كَلاَمُ الْـحَـكَمِ الْعَلِـيْمِ', 'Dan lembaran-lembaran (Shuhuf) suci yang diturunkan untuk AlKholil (Nabi Ibrohim) dan AlKaliim (Nabi Musa) mengandung Perkataan dari Yang Maha Bijaksana dan Maha Mengetahui' FROM pesantren_bab WHERE kitab_slug = 'aqidatulawam' AND bab_order = 6;
INSERT INTO pesantren_matn (bab_id, matn_order, title_id, text_ar, translation_id) SELECT id, 4, 'Bait 27', 'وَكُـلُّ مَا أَتَى بِهِ الـرَّسُـوْلُ (27) فَحَـقُّـهُ التَّسْـلِـيْمُ وَالْقَبُوْلُ', 'Dan segala apa-apa yang disampaikan oleh Rosulullah, maka kita wajib pasrah dan menerima' FROM pesantren_bab WHERE kitab_slug = 'aqidatulawam' AND bab_order = 6;
INSERT INTO pesantren_matn (bab_id, matn_order, title_id, text_ar, translation_id) SELECT id, 5, 'Bait 28', 'إِيْـمَـانُنَا بِـيَوْمِ آخِرٍ وَجَبْ (28) وَكُلِّ مَـا كَانَ بِـهِ مِنَ الْعَجَبْ', 'Keimanan kita kepada Hari Akhir hukumnya wajib, dan segala perkara yang dahsyat pada Hari Akhir' FROM pesantren_bab WHERE kitab_slug = 'aqidatulawam' AND bab_order = 6;
INSERT INTO pesantren_matn (bab_id, matn_order, title_id, text_ar, translation_id) SELECT id, 6, 'Bait 29', 'خَاتِمَةٌ فِي ذِكْرِ بَاقِي الْوَاجِبِ (29) مِمَّـا عَـلَى مُكَلَّفٍ مِنْ وَاجِبِ', 'Sebagai penutup untuk menerangkan ketetapan yang wajib, dari hal yang menjadi kewajiban bagi mukallaf' FROM pesantren_bab WHERE kitab_slug = 'aqidatulawam' AND bab_order = 6;
INSERT INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('aqidatulawam', 7, 'Sirah & Keluarga Nabi Muhammad ﷺ', 'سيرة النبي وأهل بيته');
INSERT INTO pesantren_matn (bab_id, matn_order, title_id, text_ar, translation_id) SELECT id, 1, 'Bait 30', 'نَبِـيُّـنَا مُحَمَّدٌ قَدْ أُرْسِــلاَ (30) لِلْـعَالَمِـيْـنَ رَحْـمَةً وَفُضِّلاَ', 'Nabi kita Muhammad telah diutus untuk seluruh alam sebagai Rahmat dan keutamaan diberikan kepada beliau SAW melebihi semua' FROM pesantren_bab WHERE kitab_slug = 'aqidatulawam' AND bab_order = 7;
INSERT INTO pesantren_matn (bab_id, matn_order, title_id, text_ar, translation_id) SELECT id, 2, 'Bait 31', 'أَبـُوْهُ عَبْدُ اللهِ عَبْدُ الْمُطَّلِـبْ (31) وَهَاشِـمٌ عَبْدُ مَنَافٍ يَنْتَسِـبْ', 'Ayahnya bernama Abdullah putera Abdul Mutthalib, dan nasabnya bersambung kepada Hasyim putera Abdu Manaf' FROM pesantren_bab WHERE kitab_slug = 'aqidatulawam' AND bab_order = 7;
INSERT INTO pesantren_matn (bab_id, matn_order, title_id, text_ar, translation_id) SELECT id, 3, 'Bait 32', 'وَأُمُّـهُ آمِـنَةُ الـزُّهْــرِيـَّهْ (32) أَرْضَـعَتْهُ حَلِيْمَـةُ السَّـعْدِيـَّهْ', 'Dan ibunya bernama Aminah Az-Zuhriyyah, yang menyusui beliau adalah Halimah As-Sa''diyyah' FROM pesantren_bab WHERE kitab_slug = 'aqidatulawam' AND bab_order = 7;
INSERT INTO pesantren_matn (bab_id, matn_order, title_id, text_ar, translation_id) SELECT id, 4, 'Bait 33', 'مَوْلـِدُهُ بِمَـكَّـةَ اْلأَمِيْــنَهْ (33) وَفَاتُـهُ بِـطَـيْـبَةَ الْـمَدِيْنَهْ', 'Lahirnya di Makkah yang aman, dan wafatnya di Toiybah (Madinah)' FROM pesantren_bab WHERE kitab_slug = 'aqidatulawam' AND bab_order = 7;
INSERT INTO pesantren_matn (bab_id, matn_order, title_id, text_ar, translation_id) SELECT id, 5, 'Bait 34', 'أَتَـمَّ قَـبْـلَ الْـوَحْيِ أَرْبَعِيْنَا (34) وَعُـمْـرُهُ قَدْ جَاوَزَ السِّـتِّيْنَا', 'Sebelum turun wahyu, nabi Muhammad telah sempurna berumur 40 tahun, dan usia beliau 60 tahun lebih' FROM pesantren_bab WHERE kitab_slug = 'aqidatulawam' AND bab_order = 7;
INSERT INTO pesantren_matn (bab_id, matn_order, title_id, text_ar, translation_id) SELECT id, 6, 'Bait 35', 'وَسَـبْـعَةٌ أَوْلاَدُهُ فَمِـنْـهُمُ (35) ثَلاثَـةٌ مِـنَ الذُّكـُوْرِ تُـفْهَمُ', 'Ada 7 orang putera-puteri nabi Muhammad, diantara mereka 3 orang laki-laki, maka pahamilah itu' FROM pesantren_bab WHERE kitab_slug = 'aqidatulawam' AND bab_order = 7;
INSERT INTO pesantren_matn (bab_id, matn_order, title_id, text_ar, translation_id) SELECT id, 7, 'Bait 36', 'قَاسِـمْ وَعَبْدُ اللهِ وَهْوَ الطَّيِّبُ (36) وَطَاهِـرٌ بِذَيْـنِ ذَا يُـلَـقَّبُ', 'Qasim dan Abdullah yang bergelar At-Thoyyib dan At-Thohir, dengan 2 sebutan inilah (At-Thoyyib dan At-Thohir) Abdullah diberi gelar' FROM pesantren_bab WHERE kitab_slug = 'aqidatulawam' AND bab_order = 7;
INSERT INTO pesantren_matn (bab_id, matn_order, title_id, text_ar, translation_id) SELECT id, 8, 'Bait 37', 'أَتَاهُ إبْرَاهِـيْـمُ مِنْ سُـرِّيـَّهْ (37) فَأُمُّـهُ مَارِيَّةُ الْـقِـبْـطِـيَّـهْ', 'Anak yang ketiga bernama Ibrohim dari Sariyyah (Amat perempuan), ibunya (Ibrohim) bernama Mariyah Al-Qibtiyyah' FROM pesantren_bab WHERE kitab_slug = 'aqidatulawam' AND bab_order = 7;
INSERT INTO pesantren_matn (bab_id, matn_order, title_id, text_ar, translation_id) SELECT id, 9, 'Bait 38', 'وَغَيْـرُ إِبْرَاهِيْمَ مِنْ خَـدِيْجَهْ (38) هُمْ سِتَـةٌ فَخُـذْ بِهِمْ وَلِـيْجَهْ', 'Selain Ibrohim, ibu putera-puteri Nabi Muhammad berasal dari Khodijah, mereka ada 6 orang (selain Ibrohim), maka kenalilah dengan penuh cinta' FROM pesantren_bab WHERE kitab_slug = 'aqidatulawam' AND bab_order = 7;
INSERT INTO pesantren_matn (bab_id, matn_order, title_id, text_ar, translation_id) SELECT id, 10, 'Bait 39', 'وَأَرْبَعٌ مِـنَ اْلإِنَاثِ تُـذْكَـرُ (39) رِضْـوَانُ رَبِّي لِلْجَمِـيْعِ يُذْكَرُ', 'Dan 4 orang anak perempuan Nabi akan disebutkan, semoga keridhoan Allah untuk mereka semua' FROM pesantren_bab WHERE kitab_slug = 'aqidatulawam' AND bab_order = 7;
INSERT INTO pesantren_matn (bab_id, matn_order, title_id, text_ar, translation_id) SELECT id, 11, 'Bait 40', 'فَاطِـمَـةُ الزَّهْرَاءُ بَعْلُهَا عَلِيْ (40) وَابْنَاهُمَا السِّـبْطَانِ فَضْلُهُمُ جَلِيْ', 'Fatimah Az-Zahro yang bersuamikan Ali bin Abi Tholib, dan kedua putera mereka (Hasan dan Husein) adalah cucu Nabi yang sudah jelas keutamaanya' FROM pesantren_bab WHERE kitab_slug = 'aqidatulawam' AND bab_order = 7;
INSERT INTO pesantren_matn (bab_id, matn_order, title_id, text_ar, translation_id) SELECT id, 12, 'Bait 41', 'فَزَيْـنَبٌ وَبَعْـدَهَـا رُقَـيَّهْ (41) وَأُمُّ كُـلْـثُـومٍ زَكَـتْ رَضِيَّهْ', 'Kemudian Zaenab dan selanjutnya Ruqayyah, dan Ummu Kultsum yang suci lagi diridhoi' FROM pesantren_bab WHERE kitab_slug = 'aqidatulawam' AND bab_order = 7;
INSERT INTO pesantren_matn (bab_id, matn_order, title_id, text_ar, translation_id) SELECT id, 13, 'Bait 42', 'عَنْ تِسْعِ نِسْوَةٍ وَفَاةُ الْمُصْطَفَى (42) خُيِّـرْنَ فَاخْتَرْنَ النَّـبِيَّ الْمُقْتَفَى', 'Dari 9 istri Nabi ditinggalkan setelah wafatnya, mereka semua telah diminta memilih syurga atu dunia, maka mereka memilih nabi sebagai panutan' FROM pesantren_bab WHERE kitab_slug = 'aqidatulawam' AND bab_order = 7;
INSERT INTO pesantren_matn (bab_id, matn_order, title_id, text_ar, translation_id) SELECT id, 14, 'Bait 43', 'عَائِشَـةٌ وَحَفْصَـةٌ وَسَـوْدَةُ (43) صَـفِيَّـةٌ مَـيْـمُـوْنَةٌ وَ رَمْلَةُ', 'Aisyah, Hafshah, dan Saudah, Shofiyyah, Maimunah, dan Romlah' FROM pesantren_bab WHERE kitab_slug = 'aqidatulawam' AND bab_order = 7;
INSERT INTO pesantren_matn (bab_id, matn_order, title_id, text_ar, translation_id) SELECT id, 15, 'Bait 44', 'هِنْدٌ وَ زَيْـنَبٌ كَذَا جُوَيـْرِيَهْ (44) لِلْمُـؤْمِـنِيْنَ أُمَّـهَاتٌ مَرْضِـيَّهْ', 'Hindun dan Zaenab, begitu pula Juwairiyyah, Bagi kaum Mu''minin mereka menjadi ibu-ibu yang diridhoi' FROM pesantren_bab WHERE kitab_slug = 'aqidatulawam' AND bab_order = 7;
INSERT INTO pesantren_matn (bab_id, matn_order, title_id, text_ar, translation_id) SELECT id, 16, 'Bait 45', 'حَمْـزَةُ عَمُّـهُ وعَـبَّاسٌ كَذَا (45) عَمَّـتُـهُ صَـفِيَّـةٌ ذَاتُ احْتِذَا', 'Hamzah adalah Paman Nabi demikian pula ''Abbas, Bibi Nabi adalah Shofiyyah yang mengikuti Nabi' FROM pesantren_bab WHERE kitab_slug = 'aqidatulawam' AND bab_order = 7;
INSERT INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('aqidatulawam', 8, 'Isra'' Mi''raj', 'الإسراء والمعراج');
INSERT INTO pesantren_matn (bab_id, matn_order, title_id, text_ar, translation_id) SELECT id, 1, 'Bait 46', 'وَقَبْـلَ هِجْـرَةِ النَّـبِيِّ اْلإِسْرَا (46) مِـنْ مَـكَّةَ لَيْلاً لِقُدْسٍ يُدْرَى', 'Dan sebelum Nabi Hijrah (ke Madinah), terjadi peristiwa Isro''. Dari Makkah pada malam hari menuju Baitul Maqdis yang dapat dilihat' FROM pesantren_bab WHERE kitab_slug = 'aqidatulawam' AND bab_order = 8;
INSERT INTO pesantren_matn (bab_id, matn_order, title_id, text_ar, translation_id) SELECT id, 2, 'Bait 47', 'وَبَعْدَ إِسْـرَاءٍ عُرُوْجٌ لِلسَّـمَا (47) حَتَّى رَأَى النَّـبِيُّ رَبًّـا كَـلَّمَا', 'Setelah Isro'' lalu Mi''roj (naik) keatas sehingga Nabi melihat Tuhan yang berkata-kata' FROM pesantren_bab WHERE kitab_slug = 'aqidatulawam' AND bab_order = 8;
INSERT INTO pesantren_matn (bab_id, matn_order, title_id, text_ar, translation_id) SELECT id, 3, 'Bait 48', 'مِنْ غَيْرِكَيْفٍ وَانْحِصَارٍ وَافْـتَرَضْ (48) عَلَيْهِ خَمْسًا بَعْدَ خَمْسِيْنَ فَرَضْ', 'Berkata-kata tanpa bentuk dan ruang. Disinilah diwajibkan kepadanya (sholat) 5 waktu yang sebelumnya 50 waktu' FROM pesantren_bab WHERE kitab_slug = 'aqidatulawam' AND bab_order = 8;
INSERT INTO pesantren_matn (bab_id, matn_order, title_id, text_ar, translation_id) SELECT id, 4, 'Bait 49', 'وَبَـلَّـغَ اْلأُمَّـةَ بِاْلإِسْــرَاءِ (49) وَفَـرْضِ خَـمْـسَةٍ بِلاَ امْتِرَاءِ', 'Dan Nabi telah menyampaikan kepada umat peristiwa Isro'' tersebut. Dan kewajiban sholat 5 waktu tanpa keraguan' FROM pesantren_bab WHERE kitab_slug = 'aqidatulawam' AND bab_order = 8;
INSERT INTO pesantren_matn (bab_id, matn_order, title_id, text_ar, translation_id) SELECT id, 5, 'Bait 50', 'قَدْ فَازَ صِـدِّيْقٌ بِتَصْـدِيْقٍ لَهُ (50) وَبِالْعُرُوْجِ الصِّـدْقُ وَافَى أَهْلَهُ', 'Sungguh beruntung sahabat Abubakar As-Shiddiq dengan membenarkan peristiwa tersebut, juga peristiwa Mi''raj yang sudah sepantasnya kebenaran itu disandang bagi pelaku Isro'' Mi''roj' FROM pesantren_bab WHERE kitab_slug = 'aqidatulawam' AND bab_order = 8;
INSERT INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('aqidatulawam', 9, 'Khatimah (Penutup)', 'الخاتمة');
INSERT INTO pesantren_matn (bab_id, matn_order, title_id, text_ar, translation_id) SELECT id, 1, 'Bait 51', 'وَهَـذِهِ عَقِيْـدَةٌ مُخْـتَصَرَهْ (51) وَلِلْـعَـوَامِ سَـهْـلَةٌ مُيَسَّرَهْ', 'Inilah keterangan Aqidah secara ringkas bagi orang-orang awam yang mudah dan gampang' FROM pesantren_bab WHERE kitab_slug = 'aqidatulawam' AND bab_order = 9;
INSERT INTO pesantren_matn (bab_id, matn_order, title_id, text_ar, translation_id) SELECT id, 2, 'Bait 52', 'نَاظِمُ تِلْكَ أَحْـمَدُ الْمَرْزُوْقِيْ (52) مَنْ يَنْتَمِي لِلصَّـادِقِ الْمَصْدُوْقِ', 'Yang di nadhomkan oleh Ahmad Al Marzuqi, seorang yang bernisbat kepada Nabi Muhammad (As-Shodiqul Mashduq)' FROM pesantren_bab WHERE kitab_slug = 'aqidatulawam' AND bab_order = 9;
INSERT INTO pesantren_matn (bab_id, matn_order, title_id, text_ar, translation_id) SELECT id, 3, 'Bait 53', 'وَ الْحَمْدُ ِللهِ وَصَـلَّى سَـلَّمَا (53) عَلَـى النَّبِيِّ خَيْرِ مَنْ قَدْ عَلَّـمَا', 'Dan segala puji bagi Allah serta Sholawat dan Salam tercurahkan kepada Nabi sebaik-baik orang yang telah mengajar' FROM pesantren_bab WHERE kitab_slug = 'aqidatulawam' AND bab_order = 9;
INSERT INTO pesantren_matn (bab_id, matn_order, title_id, text_ar, translation_id) SELECT id, 4, 'Bait 54', 'وَاْلآلِ وَالصَّـحْبِ وَكُلِّ مُرْشِدِ (54) وَكُلِّ مَـنْ بِخَيْرِ هَدْيٍ يَقْتَدِيْ', 'Juga kepada keluarga dan sahabat serta orang yang memberi petunjuk dan orang yang mengikuti petunjuk' FROM pesantren_bab WHERE kitab_slug = 'aqidatulawam' AND bab_order = 9;
INSERT INTO pesantren_matn (bab_id, matn_order, title_id, text_ar, translation_id) SELECT id, 5, 'Bait 55', 'وَأَسْـأَلُ الْكَرِيْمَ إِخْلاَصَ الْعَمَلْ (55) ونَفْعَ كُلِّ مَنْ بِهَا قَدِ اشْـتَغَلْ', 'Dan saya mohon kepada Allah yang Maha Pemurah keikhlasan dalam beramal dan manfaat bagi setiap orang yang berpegang teguh pada aqidah ini' FROM pesantren_bab WHERE kitab_slug = 'aqidatulawam' AND bab_order = 9;
INSERT INTO pesantren_matn (bab_id, matn_order, title_id, text_ar, translation_id) SELECT id, 6, 'Bait 56', 'أَبْيَاتُهَا ( مَيْـزٌ ) بِـعَدِّ الْجُمَلِ (56) تَارِيْخُهَا ( لِيْ حَيُّ غُرٍّ ) جُمَلِ', 'Nadhom ini ada 57 bait dengan hitungan abjad, tahun penulisannya 1258 Hijriah' FROM pesantren_bab WHERE kitab_slug = 'aqidatulawam' AND bab_order = 9;
INSERT INTO pesantren_matn (bab_id, matn_order, title_id, text_ar, translation_id) SELECT id, 7, 'Bait 57', 'سَـمَّيْـتُهَا عَـقِـيْدَةَ الْعَوَامِ (57) مِـنْ وَاجِبٍ فِي الدِّيْنِ بِالتَّمَامِ', 'Aku namakan aqidah ini Aqidatul Awwam, keterangan yang wajib diketahui dalam urusan agama dengan sempurna' FROM pesantren_bab WHERE kitab_slug = 'aqidatulawam' AND bab_order = 9;
